class Solution:
    def maxPoints(self, technique1, technique2, k):
        n = len(technique1)
        best = None
        for mask in range(1 << n):
            cnt1 = bin(mask).count('1')
            if cnt1 < k:
                continue
            total = 0
            for i in range(n):
                if (mask >> i) & 1:
                    total += technique1[i]
                else:
                    total += technique2[i]
            if best is None or total > best:
                best = total
        return best

