class Solution:
    def maxPoints(self, technique1: List[int], technique2: List[int], k: int) -> int:
        n = len(technique1)
        gains = sorted((technique1[i] - technique2[i] for i in range(n)), reverse=True)
        pos = sum(1 for g in gains if g > 0)
        m = max(k, pos)
        base = sum(technique2)
        return base + sum(gains[:m])

