var maxPoints = function(technique1, technique2, k) {
    const gains = technique1.map((v, i) => v - technique2[i]).sort((a, b) => b - a);
    const pos = gains.filter(g => g > 0).length;
    const m = Math.max(k, pos);
    const base = technique2.reduce((a, b) => a + b, 0);
    let s = 0;
    for (let i = 0; i < m; i++) s += gains[i];
    return base + s;
};
